create table dirkspzm32.s_qs_status (
    sid                  varchar2(2 char) default 01 not null enable,
    firma_nr             number(2, 0) not null enable,
    lte_id               varchar2(20 char) not null enable,
    status               varchar2(3 char) not null enable,
    laborstatus          varchar2(1 char) not null enable,
    labortext            varchar2(30 char) not null enable,
    fehler_code          number(*, 5),
    fehler_text          varchar2(2500 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.s_qs_status
    add constraint check_s_qs_status_status
        check ( status in ( 'N', 'U', 'UE', 'ERR' ) ) enable;

alter table dirkspzm32.s_qs_status
    add constraint pk_s_qs_status primary key ( lte_id,
                                                created_date )
        using index enable;


